    text-overflow: ellipsis;
}

.channel-desc {
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    position: absolute;
    top: 8px;
    right: 12px;
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main Message Area ── */

.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-right: 1px solid #ddd;
    transition: width 0.2s ease;
}

    .message-area.expanded {
        width: 80%;
    }

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #ddd;
    flex-shrink: 0;
}

    .message-header h3 {
        margin: 0;
        font-size: 1.1rem;
        font-weight: 700;
    }

.channel-description {
    font-size: 0.85rem;
    color: #616061;
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    color: #888;
    padding: 10px;
    font-size: 0.85rem;
}

.message-bubble {
    position: relative;
    padding: 8px 12px;
    border-radius: 6px;
    margin-bottom: 4px;
    transition: background 0.1s;
}

    .message-bubble:hover {
        background: #f8f8f8;
    }

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.95rem;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.1s;
}

    .reaction-badge:hover {
        background: #e0e0ff;
        border-color: #aaf;
    }

/* ── Thread link ── */

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

    .thread-link:hover {
        text-decoration: underline;
    }

/* ── Message Actions (hover) ── */

.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.12);
    padding: 2px;
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

    .action-btn:hover {
        background: #f0f0f0;
    }

/* ── Emoji Picker ── */

.emoji-picker-wrapper {
    position: relative;
