@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_e5a5e59909344ac2adb14ba7361ec352.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="chat-app">
    @* ── Left Sidebar ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h2>Channels</h2>
        </div>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(threadOpen ? "" : "expanded")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h3># @activeChannel.Name</h3>
                <span class="channel-description">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScroll">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-bubble" @onmouseenter="() => hoveredMessageId = msg.Id"
                         @onmouseleave="() => hoveredMessageId = null">
                        <div class="message-meta">
                            <span class="author">@msg.Author</span>
                            <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                        </div>
                        <div class="message-content">@msg.Content</div>

                        @if (msg.Reactions.Count > 0)
                        {
                            <div class="reaction-row">
                                @foreach (var r in msg.Reactions)
                                {
                                    <button class="reaction-badge" @onclick="() => AddReactionAsync(msg.Id, r.Emoji)"
                                            title="@string.Join(", ", r.Users)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }

                        @{ var threadSummary = threadSummaries.GetValueOrDefault(msg.Id); }
                        @if (threadSummary is not null)
                        {
                            <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                @threadSummary.ReplyCount @(threadSummary.ReplyCount == 1 ? "reply" : "replies")
                            </button>
                        }

                        @if (hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" @onclick="() => OpenThreadAsync(msg.Id)" title="Reply in thread">
                                    💬 Reply
                                </button>
                                <div class="emoji-picker-wrapper">
                                    <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)" title="Add reaction">
                                        😀 React
                                    </button>
                                    @if (emojiPickerMessageId == msg.Id)
                                    {
                                        <div class="emoji-picker">
                                            @foreach (var emoji in commonEmojis)
                                            {
                                                <button class="emoji-option" @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                    @emoji
                                                </button>
                                            }
                                        </div>
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnMessageKeyDown"
                          placeholder="Message #@activeChannel.Name" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Thread Panel ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@threadRootMessage.Author</span>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-messages">
                @foreach (var reply in threadReplies)
                {
                    <div class="message-bubble">
                        <div class="message-meta">
                            <span class="author">@reply.Author</span>
                            <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="message-content">@reply.Content</div>

                        @if (reply.Reactions.Count > 0)
                        {
                            <div class="reaction-row">
                                @foreach (var r in reply.Reactions)
                                {
                                    <button class="reaction-badge" @onclick="() => AddReactionAsync(reply.Id, r.Emoji)"
                                            title="@string.Join(", ", r.Users)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown"
                          placeholder="Reply…" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "👀", "🔥"];

    // Data
    private List<Channel> channels = [];
    private Channel? activeChannel;
    private int activeChannelId;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private int skip;
    private bool hasMoreMessages = true;
    private bool isLoadingMore;

    // Thread state
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private string threadReplyText = "";

    // UI state
    private string newMessageText = "";
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private ElementReference messageListRef;
    private IJSObjectReference? jsModule;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./_content/sv-e5a5e59909344ac2adb14ba7361ec352/Components/Pages/Chat.razor.js");
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        skip = 0;
        hasMoreMessages = true;
        messages.Clear();
        threadSummaries.Clear();
        CloseThread();
        emojiPickerMessageId = null;

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        skip = loaded.Count;
        hasMoreMessages = loaded.Count == PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        // Refresh the channel list to clear the badge
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottom();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages || activeChannel is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, skip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            skip += older.Count;
            BuildThreadSummaries();
        }
        hasMoreMessages = older.Count == PageSize;
        isLoadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var replies = messages.Where(m => m.ReplyToId.HasValue).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private async Task OnMessageListScroll()
    {
        if (jsModule is null) return;
        var scrollTop = await jsModule.InvokeAsync<double>("getScrollTop", messageListRef);
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages.Add(sent);
        skip++;
        newMessageText = "";

        await ScrollToBottom();
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    // ── Thread ──

    private async Task OpenThreadAsync(int rootMessageId)
    {
        emojiPickerMessageId = null;
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId)
                            ?? threadReplies.FirstOrDefault();
        // Remove root from replies if present
        threadReplies = threadReplies.Where(m => m.Id != rootMessageId).ToList();
        threadReplyText = "";
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
        threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null)
            return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        messages.Add(reply);
        skip++;
        BuildThreadSummaries();
        threadReplyText = "";
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh the message list to show updated reactions
        if (activeChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(activeChannel.Id, 0, skip);
            messages = refreshed;
            BuildThreadSummaries();
        }

        if (threadOpen && threadRootMessage is not null)
        {
            threadReplies = (await ChatService.GetThreadAsync(threadRootMessage.Id))
                .Where(m => m.Id != threadRootMessage.Id).ToList();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Helpers ──

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length <= 50 ? desc : desc[..47] + "…";
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            await jsModule.DisposeAsync();
        }
    }
}

